import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App.jsx';
import './styles.css';

ReactDOM.createRoot(document.getElementById('root')).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
);

import React, { useEffect, useState } from 'react';
import { createProfileSnapshot } from './features/profile/profilePlan.js';
import { SliceEntryBridge } from './features/health-item-detail-and-completion/SliceEntryBridge.jsx';
import { OnboardingRoute } from './routes/onboarding.jsx';

const DEFAULT_DRAFT = {
  ageYears: '',
  gender: '',
};

export default function App() {
  const [screen, setScreen] = useState('welcome');
  const [draft, setDraft] = useState(DEFAULT_DRAFT);
  const [pendingDraft, setPendingDraft] = useState(null);
  const [profile, setProfile] = useState(null);

  useEffect(() => {
    if (screen !== 'generating' || !pendingDraft) {
      return undefined;
    }

    const timerId = globalThis.setTimeout(() => {
      const nextProfile = createProfileSnapshot(pendingDraft);
      setProfile(nextProfile);
      setPendingDraft(null);
      setScreen('dashboard');
    }, 160);

    return () => globalThis.clearTimeout(timerId);
  }, [pendingDraft, screen]);

  if (screen === 'welcome') {
    return (
      <main className="app-shell">
        <section className="panel hero welcome-hero">
          <p className="eyebrow">Longevity Health OS</p>
          <h1>Your preventive plan starts with two answers</h1>
          <p className="lede">A self-only flow turns age and gender into a dashboard in seconds.</p>
          <div className="actions">
            <button
              type="button"
              className="primary"
              onClick={() => {
                setScreen('onboarding');
              }}
            >
              Start
            </button>
          </div>
          <p className="helper">Rule-based guidance only. Not a medical record.</p>
        </section>
      </main>
    );
  }

  if (screen === 'onboarding') {
    return (
      <OnboardingRoute
        draft={draft}
        onDraftChange={(updates) => {
          setDraft((current) => ({ ...current, ...updates }));
        }}
        onSubmit={(nextDraft) => {
          setPendingDraft(nextDraft);
          setScreen('generating');
        }}
        onBack={() => {
          setScreen('welcome');
        }}
      />
    );
  }

  if (screen === 'generating') {
    return <GeneratingScreen draft={pendingDraft ?? draft} />;
  }

  return (
    <SliceEntryBridge
      profile={profile}
      onProfileChange={setProfile}
      onRestart={() => {
        setProfile(null);
        setDraft(DEFAULT_DRAFT);
        setPendingDraft(null);
        setScreen('welcome');
      }}
    />
  );
}

function GeneratingScreen({ draft }) {
  return (
    <main className="app-shell">
      <section className="panel hero generating-panel">
        <div className="loading-mark" aria-hidden="true" />
        <p className="eyebrow">Building your dashboard</p>
        <h1>We are generating your first plan</h1>
        <p className="lede">
          Age {draft?.ageYears || '—'} · {capitalize(draft?.gender) || '—'}
        </p>
        <p className="helper">The plan is created locally before the dashboard appears.</p>
      </section>
    </main>
  );
}

function capitalize(value) {
  if (!value) {
    return '';
  }

  return value.charAt(0).toUpperCase() + value.slice(1);
}

:root {
  font-family: "IBM Plex Sans", "Avenir Next", "Segoe UI", sans-serif;
  color: #172026;
  background: radial-gradient(circle at top, #f5f8ff, #eef4f4 58%, #eef0f7);
  line-height: 1.4;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
}

h1,
h2,
h3,
p {
  margin: 0;
}

.app-shell {
  min-height: 100vh;
  padding: 20px 14px 36px;
}

.panel {
  max-width: 760px;
  margin: 0 auto;
  background: #ffffffd4;
  border: 1px solid #d7dde8;
  border-radius: 16px;
  padding: 18px;
  box-shadow: 0 14px 36px #1f2f4612;
}

.hero {
  text-align: center;
  padding: 34px 20px;
}

.eyebrow {
  letter-spacing: 0.07em;
  text-transform: uppercase;
  color: #42526a;
  font-size: 0.75rem;
}

.lede {
  color: #324356;
  margin-top: 10px;
}

.helper {
  color: #4b5a6e;
  font-size: 0.88rem;
  margin-top: 14px;
}

.actions {
  margin-top: 16px;
  display: flex;
  justify-content: center;
  gap: 8px;
}

button {
  font: inherit;
  border-radius: 10px;
  border: 1px solid #9aa8bf;
  color: #18212d;
  background: #fff;
  padding: 10px 14px;
  cursor: pointer;
}

button:disabled {
  cursor: not-allowed;
  opacity: 0.55;
}

button.primary {
  background: #0f4c81;
  border-color: #0f4c81;
  color: #fff;
}

button.secondary {
  background: #f7f9fc;
}

.loading-mark {
  width: 46px;
  height: 46px;
  margin: 0 auto 14px;
  border-radius: 999px;
  border: 5px solid #d3ddef;
  border-top-color: #0f4c81;
  animation: spin 0.9s linear infinite;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

.form {
  margin-top: 18px;
  display: grid;
  gap: 12px;
}

.field {
  display: grid;
  gap: 6px;
}

.field label {
  font-weight: 600;
}

.field input,
.field select {
  width: 100%;
  border: 1px solid #c4cede;
  border-radius: 10px;
  padding: 10px;
  font: inherit;
  background: #fff;
}

.error {
  color: #a12525;
  font-size: 0.9rem;
}

.dashboard {
  display: grid;
  gap: 16px;
}

.dashboard-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
}

.score {
  border: 1px solid #c6d4eb;
  border-radius: 12px;
  padding: 10px 12px;
  background: #f2f7ff;
  font-weight: 600;
}

.group {
  display: grid;
  gap: 8px;
}

.group h3 {
  font-size: 1.05rem;
}

.card-list {
  display: grid;
  gap: 8px;
}

.item-card {
  width: 100%;
  text-align: left;
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
  border: 1px solid #cdd6e4;
  border-radius: 12px;
  padding: 12px;
  background: #fff;
}

.item-meta {
  font-size: 0.86rem;
  color: #4e5f73;
}

.status-chip {
  border-radius: 999px;
  padding: 5px 9px;
  font-size: 0.78rem;
  font-weight: 700;
  color: #16395f;
  background: #ddebff;
  border: 1px solid #bcd2f8;
  white-space: nowrap;
}

.detail {
  display: grid;
  gap: 14px;
}

.detail-head {
  display: grid;
  gap: 8px;
}

.detail-section {
  border: 1px solid #d6deea;
  border-radius: 12px;
  padding: 10px;
  background: #fff;
  display: grid;
  gap: 6px;
}

.detail-section h3 {
  font-size: 0.95rem;
}

.detail-actions {
  position: sticky;
  bottom: 10px;
  display: grid;
  gap: 8px;
  background: #f6f8fd;
  padding: 10px;
  border: 1px solid #d3dced;
  border-radius: 12px;
}

.message {
  font-size: 0.9rem;
}

.message.success {
  color: #1f6b2c;
}

.empty {
  color: #4c5c6f;
  font-size: 0.92rem;
}

@media (min-width: 768px) {
  .app-shell {
    padding: 30px 20px 44px;
  }

  .panel {
    padding: 24px;
  }
}

import React, { useState } from 'react';
import { ProfileForm } from '../profile/ProfileForm.jsx';

export function OnboardingPage({ draft, onDraftChange, onSubmit, onBack }) {
  const [error, setError] = useState('');

  const handleSubmit = () => {
    const nextAge = String(draft.ageYears || '').trim();
    const ageValue = Number(nextAge);

    if (!Number.isInteger(ageValue) || ageValue < 18 || ageValue > 120) {
      setError('Enter a valid age between 18 and 120.');
      return;
    }

    if (!draft.gender) {
      setError('Select a gender to continue.');
      return;
    }

    setError('');
    onSubmit({ ageYears: nextAge, gender: draft.gender });
  };

  return (
    <main className="app-shell">
      <section className="panel">
        <p className="eyebrow">Onboarding</p>
        <h1>Tell us who this plan is for</h1>
        <p className="lede">We use age and gender to generate your first preventive health dashboard.</p>

        <ProfileForm
          draft={draft}
          onDraftChange={onDraftChange}
          onSubmit={handleSubmit}
          onBack={onBack}
          error={error}
        />
      </section>
    </main>
  );
}

import React from 'react';

export function ProfileForm({ draft, onDraftChange, onSubmit, onBack, error }) {
  return (
    <div className="form" role="form" aria-label="Profile onboarding form">
      <div className="field">
        <label htmlFor="ageYears">Age</label>
        <input
          id="ageYears"
          name="ageYears"
          inputMode="numeric"
          min="18"
          max="120"
          value={draft.ageYears}
          onChange={(event) => {
            onDraftChange({ ageYears: event.target.value });
          }}
        />
      </div>

      <div className="field">
        <label htmlFor="gender">Gender</label>
        <select
          id="gender"
          name="gender"
          value={draft.gender}
          onChange={(event) => {
            onDraftChange({ gender: event.target.value });
          }}
        >
          <option value="">Select one</option>
          <option value="female">Female</option>
          <option value="male">Male</option>
          <option value="other">Other</option>
        </select>
      </div>

      {error ? <p className="error">{error}</p> : null}

      <div className="actions">
        <button type="button" className="secondary" onClick={onBack}>
          Back
        </button>
        <button type="button" className="primary" onClick={onSubmit}>
          Generate dashboard
        </button>
      </div>
    </div>
  );
}

export function calculateHealthScore(items) {
  if (!Array.isArray(items) || items.length === 0) {
    return 0;
  }

  const doneCount = items.reduce((count, item) => {
    return item.status === 'Done' ? count + 1 : count;
  }, 0);

  return Math.round((doneCount / items.length) * 100);
}

import { HEALTH_ITEM_STATUS } from '../health-item-detail-and-completion/model.js';
import { calculateHealthScore } from './healthScore.js';

export function createProfileSnapshot(draft) {
  const nowIso = new Date().toISOString();
  const profileId = 'profile-primary';
  const ageYears = Number(draft.ageYears);
  const gender = String(draft.gender || '').toLowerCase();

  const healthItems = buildInitialItems(profileId, ageYears, gender, nowIso);

  return {
    id: profileId,
    ageYears,
    gender,
    healthItems,
    healthScore: calculateHealthScore(healthItems),
  };
}

function buildInitialItems(profileId, ageYears, gender, nowIso) {
  const baseItems = [
    {
      id: 'bp-check',
      title: 'Blood pressure check',
      actionLabel: 'Book a blood pressure check and record the result.',
      whyItMatters: 'High blood pressure can stay silent and increase long-term heart risk.',
      recommendationFrequency: 'At least once every 12 months.',
      priorityHorizon: 'Today',
      status: HEALTH_ITEM_STATUS.DUE,
      nextDueDate: '2026-05-10',
      plannedForDate: null,
      lastCompletedAt: null,
    },
    {
      id: 'lipid-panel',
      title: 'Lipid panel',
      actionLabel: 'Schedule a fasting lipid panel with your clinic or lab.',
      whyItMatters: 'Cholesterol trends guide prevention choices before symptoms appear.',
      recommendationFrequency: 'Every 3 to 5 years for low-risk adults.',
      priorityHorizon: 'Soon',
      status: HEALTH_ITEM_STATUS.PLANNED,
      nextDueDate: null,
      plannedForDate: '2026-06-02',
      lastCompletedAt: null,
    },
    {
      id: 'dental-cleaning',
      title: 'Dental cleaning',
      actionLabel: 'Set your next cleaning appointment with your dentist.',
      whyItMatters: 'Routine oral care helps prevent gum disease and supports overall health.',
      recommendationFrequency: 'Every 6 months.',
      priorityHorizon: 'Later',
      status: HEALTH_ITEM_STATUS.DUE,
      nextDueDate: '2026-08-15',
      plannedForDate: null,
      lastCompletedAt: null,
    },
  ];

  return baseItems.map((item) => {
    const tailoredWhy =
      ageYears >= 50
        ? `${item.whyItMatters} This is especially important after age 50.`
        : item.whyItMatters;

    const genderNote =
      gender === 'female'
        ? ' Guidance is adjusted for female preventive pathways.'
        : gender === 'male'
          ? ' Guidance is adjusted for male preventive pathways.'
          : '';

    return {
      ...item,
      profileId,
      whyItMatters: `${tailoredWhy}${genderNote}`.trim(),
      updatedAt: nowIso,
    };
  });
}

import React from 'react';
import { OnboardingPage } from '../features/onboarding/OnboardingPage.jsx';

export function OnboardingRoute({ draft, onDraftChange, onSubmit, onBack }) {
  return <OnboardingPage draft={draft} onDraftChange={onDraftChange} onSubmit={onSubmit} onBack={onBack} />;
}

import { calculateHealthScore } from '../profile/healthScore.js';

export const HEALTH_ITEM_STATUS = Object.freeze({
  DUE: 'Due',
  PLANNED: 'Planned',
  DONE: 'Done',
});

const ELIGIBLE_FOR_COMPLETION = new Set([HEALTH_ITEM_STATUS.DUE, HEALTH_ITEM_STATUS.PLANNED]);

export function getHealthItemById(profile, healthItemId) {
  if (!profile || !Array.isArray(profile.healthItems)) {
    return null;
  }

  return profile.healthItems.find((item) => item.id === healthItemId) ?? null;
}

export function isCompletionEligible(item) {
  return Boolean(item && ELIGIBLE_FOR_COMPLETION.has(item.status));
}

export function deriveStatusContext(item) {
  if (!item) {
    return '';
  }

  if (item.status === HEALTH_ITEM_STATUS.DUE) {
    return item.nextDueDate ? `Due by ${formatDate(item.nextDueDate)}.` : 'Due now.';
  }

  if (item.status === HEALTH_ITEM_STATUS.PLANNED) {
    return item.plannedForDate ? `Planned for ${formatDate(item.plannedForDate)}.` : 'Planned.';
  }

  return item.lastCompletedAt
    ? `Completed on ${formatDate(item.lastCompletedAt)}.`
    : 'Completed.';
}

export function createHealthItemDetailViewModel(profile, healthItemId) {
  const item = getHealthItemById(profile, healthItemId);
  if (!item) {
    return null;
  }

  return {
    id: item.id,
    title: item.title,
    actionLabel: item.actionLabel,
    recommendationFrequency: item.recommendationFrequency,
    whyItMatters: item.whyItMatters,
    status: item.status,
    statusContext: deriveStatusContext(item),
    isEligibleForCompletion: isCompletionEligible(item),
  };
}

export function markHealthItemDone(profile, healthItemId, completedAtIso = new Date().toISOString()) {
  if (!profile || !Array.isArray(profile.healthItems)) {
    throw new Error('Profile is required.');
  }

  const target = profile.healthItems.find((item) => item.id === healthItemId);

  if (!target) {
    throw new Error('Health item not found.');
  }

  if (target.profileId !== profile.id) {
    throw new Error('Cross-profile access is not allowed.');
  }

  if (!isCompletionEligible(target)) {
    throw new Error('Item is already done.');
  }

  const nextHealthItems = profile.healthItems.map((item) => {
    if (item.id !== healthItemId) {
      return item;
    }

    return {
      ...item,
      status: HEALTH_ITEM_STATUS.DONE,
      lastCompletedAt: completedAtIso,
      plannedForDate: null,
      updatedAt: completedAtIso,
    };
  });

  return {
    ...profile,
    healthItems: nextHealthItems,
    healthScore: calculateHealthScore(nextHealthItems),
  };
}

export function groupDashboardItems(healthItems) {
  const groups = {
    Today: [],
    Soon: [],
    Later: [],
  };

  for (const item of healthItems || []) {
    if (item.status === HEALTH_ITEM_STATUS.DONE) {
      continue;
    }

    if (item.priorityHorizon === 'Today' || item.priorityHorizon === 'Soon' || item.priorityHorizon === 'Later') {
      groups[item.priorityHorizon].push(item);
    }
  }

  return groups;
}

function formatDate(rawValue) {
  const date = new Date(rawValue);
  if (Number.isNaN(date.getTime())) {
    return 'unknown date';
  }

  return new Intl.DateTimeFormat('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  }).format(date);
}

import React from 'react';
import { HealthItemDetailAndCompletionRoute } from '../../routes/health-item-detail-and-completion.jsx';

export function SliceEntryBridge({ profile, onProfileChange, onRestart }) {
  return (
    <HealthItemDetailAndCompletionRoute
      profile={profile}
      onProfileChange={onProfileChange}
      onRestart={onRestart}
    />
  );
}

import React, { useMemo, useState } from 'react';
import {
  createHealthItemDetailViewModel,
  groupDashboardItems,
  markHealthItemDone,
} from '../features/health-item-detail-and-completion/model.js';

export function HealthItemDetailAndCompletionRoute({ profile, onProfileChange, onRestart }) {
  const [selectedItemId, setSelectedItemId] = useState(null);
  const [isSaving, setIsSaving] = useState(false);
  const [saveError, setSaveError] = useState('');
  const [saveSuccess, setSaveSuccess] = useState('');

  const grouped = useMemo(() => groupDashboardItems(profile?.healthItems ?? []), [profile]);

  if (!profile) {
    return (
      <main className="app-shell">
        <section className="panel">
          <h1>No active profile</h1>
        </section>
      </main>
    );
  }

  if (selectedItemId) {
    const detail = createHealthItemDetailViewModel(profile, selectedItemId);

    if (!detail) {
      return (
        <main className="app-shell">
          <section className="panel detail">
            <h1>Could not load item details</h1>
            <p className="error">The selected health item is unavailable right now.</p>
            <div className="actions" style={{ justifyContent: 'flex-start' }}>
              <button
                type="button"
                className="secondary"
                onClick={() => {
                  setSelectedItemId(null);
                  setSaveError('');
                  setSaveSuccess('');
                }}
              >
                Try again
              </button>
            </div>
          </section>
        </main>
      );
    }

    const handleMarkDone = () => {
      setSaveError('');
      setSaveSuccess('');
      setIsSaving(true);

      try {
        const nextProfile = markHealthItemDone(profile, detail.id);
        onProfileChange(nextProfile);
        setSaveSuccess('Saved. Item marked Done.');
      } catch (error) {
        setSaveError(error instanceof Error ? error.message : 'Unable to save right now.');
      } finally {
        setIsSaving(false);
      }
    };

    return (
      <main className="app-shell">
        <section className="panel detail">
          <div className="detail-head">
            <div className="actions" style={{ justifyContent: 'flex-start', marginTop: 0 }}>
              <button
                type="button"
                className="secondary"
                onClick={() => {
                  setSelectedItemId(null);
                  setSaveError('');
                  setSaveSuccess('');
                }}
              >
                Back to dashboard
              </button>
            </div>
            <p className="eyebrow">Health item</p>
            <h1>{detail.title}</h1>
            <span className="status-chip">{detail.status}</span>
          </div>

          <section className="detail-section">
            <h3>Action</h3>
            <p>{detail.actionLabel}</p>
          </section>

          <section className="detail-section">
            <h3>Recommendation frequency</h3>
            <p>{detail.recommendationFrequency}</p>
          </section>

          <section className="detail-section">
            <h3>Why it matters</h3>
            <p>{detail.whyItMatters}</p>
          </section>

          <section className="detail-section">
            <h3>Status context</h3>
            <p>{detail.statusContext}</p>
          </section>

          <section className="detail-actions" aria-live="polite">
            {detail.isEligibleForCompletion ? (
              <button type="button" className="primary" disabled={isSaving} onClick={handleMarkDone}>
                {isSaving ? 'Saving...' : 'Mark as Done'}
              </button>
            ) : null}
            {saveError ? <p className="message error">{saveError}</p> : null}
            {saveSuccess ? <p className="message success">{saveSuccess}</p> : null}
          </section>
        </section>
      </main>
    );
  }

  return (
    <main className="app-shell">
      <section className="panel dashboard">
        <header className="dashboard-header">
          <div>
            <p className="eyebrow">Dashboard</p>
            <h1>Prioritized health items</h1>
          </div>
          <div className="score">Health Score: {profile.healthScore}%</div>
        </header>

        <div className="actions" style={{ justifyContent: 'flex-start', marginTop: 0 }}>
          <button type="button" className="secondary" onClick={onRestart}>
            Start over
          </button>
        </div>

        {['Today', 'Soon', 'Later'].map((groupName) => {
          const items = grouped[groupName];

          return (
            <section className="group" key={groupName}>
              <h3>{groupName}</h3>
              <div className="card-list">
                {items.length > 0 ? (
                  items.map((item) => (
                    <button
                      type="button"
                      key={item.id}
                      className="item-card"
                      onClick={() => {
                        setSelectedItemId(item.id);
                        setSaveError('');
                        setSaveSuccess('');
                      }}
                    >
                      <span>
                        <strong>{item.title}</strong>
                        <span className="item-meta">Tap to view details</span>
                      </span>
                      <span className="status-chip">{item.status}</span>
                    </button>
                  ))
                ) : (
                  <p className="empty">No items in this group.</p>
                )}
              </div>
            </section>
          );
        })}
      </section>
    </main>
  );
}

import test from 'node:test';
import assert from 'node:assert/strict';
import { createProfileSnapshot } from '../../src/features/profile/profilePlan.js';

test('onboarding snapshot creates profile and initial dashboard data', () => {
  const profile = createProfileSnapshot({ ageYears: '42', gender: 'female' });

  assert.equal(profile.id, 'profile-primary');
  assert.equal(profile.ageYears, 42);
  assert.equal(profile.gender, 'female');
  assert.ok(Array.isArray(profile.healthItems));
  assert.ok(profile.healthItems.length >= 3);
  assert.equal(typeof profile.healthScore, 'number');

  for (const item of profile.healthItems) {
    assert.ok(item.id);
    assert.ok(item.profileId === profile.id);
    assert.ok(item.actionLabel);
    assert.ok(item.whyItMatters);
    assert.ok(item.recommendationFrequency);
    assert.ok(item.status === 'Due' || item.status === 'Planned' || item.status === 'Done');
  }
});

import test from 'node:test';
import assert from 'node:assert/strict';
import { createProfileSnapshot } from '../../src/features/profile/profilePlan.js';
import {
  HEALTH_ITEM_STATUS,
  createHealthItemDetailViewModel,
  groupDashboardItems,
  markHealthItemDone,
} from '../../src/features/health-item-detail-and-completion/model.js';
import { calculateHealthScore } from '../../src/features/profile/healthScore.js';

test('every dashboard item resolves to a detail view for the same item id', () => {
  const profile = createProfileSnapshot({ ageYears: '39', gender: 'male' });
  const grouped = groupDashboardItems(profile.healthItems);
  const dashboardItems = [...grouped.Today, ...grouped.Soon, ...grouped.Later];

  assert.ok(dashboardItems.length > 0);

  for (const item of dashboardItems) {
    const detail = createHealthItemDetailViewModel(profile, item.id);
    assert.ok(detail);
    assert.equal(detail.id, item.id);
  }
});

test('detail view model contains required action, frequency, why, status and context', () => {
