test('marking eligible item done updates item status and keeps done after reopen', () => {
  const profile = createProfileSnapshot({ ageYears: '45', gender: 'other' });
  const target = profile.healthItems.find((item) => item.status !== HEALTH_ITEM_STATUS.DONE);

  assert.ok(target);

  const updated = markHealthItemDone(profile, target.id, '2026-04-29T09:30:00.000Z');
  const reopened = createHealthItemDetailViewModel(updated, target.id);

  assert.ok(reopened);
  assert.equal(reopened.status, HEALTH_ITEM_STATUS.DONE);

  const updatedItem = updated.healthItems.find((item) => item.id === target.id);
  assert.ok(updatedItem);
  assert.equal(updatedItem.lastCompletedAt, '2026-04-29T09:30:00.000Z');
  assert.equal(updatedItem.plannedForDate, null);

  assert.throws(() => {
    markHealthItemDone(updated, target.id);
  }, /already done/i);
});

test('completed item is removed from dashboard groups and never duplicated', () => {
  const profile = createProfileSnapshot({ ageYears: '40', gender: 'female' });
  const firstToday = groupDashboardItems(profile.healthItems).Today[0];

  assert.ok(firstToday);

  const updated = markHealthItemDone(profile, firstToday.id, '2026-04-29T10:00:00.000Z');
  const grouped = groupDashboardItems(updated.healthItems);
  const ids = [...grouped.Today, ...grouped.Soon, ...grouped.Later].map((item) => item.id);

  assert.equal(ids.includes(firstToday.id), false);

  const uniqueCount = new Set(ids).size;
  assert.equal(uniqueCount, ids.length);
});

